<script setup>defineProps({label:String,value:[String,Number],icon:String,tone:{type:String,default:'red'}})</script>
<template><div :class="['stat',tone]"><div class="icon"><span class="material-icons-outlined">{{icon}}</span></div><strong>{{value}}</strong><span>{{label}}</span></div></template>
<style scoped>.stat{min-height:120px;padding:16px;border:1px solid #e2e8f0;border-top:3px solid var(--tone);border-radius:20px;background:#fff;box-shadow:0 8px 24px #0f172a0c}.icon{width:38px;height:38px;border-radius:13px;background:var(--soft);color:var(--tone);display:grid;place-items:center}.stat strong,.stat>span{display:block}.stat strong{margin-top:9px;font-size:24px}.stat>span{color:#64748b;font-size:11px;font-weight:800}.red{--tone:#dc2626;--soft:#fee2e2}.green{--tone:#16a34a;--soft:#dcfce7}.blue{--tone:#2563eb;--soft:#dbeafe}.violet{--tone:#7c3aed;--soft:#ede9fe}@media(max-width:600px){.stat{min-height:96px;padding:12px;border-radius:16px}.icon{width:32px;height:32px}.stat strong{font-size:20px}}</style>
